// StripeOverride implements an escape-hatch action that resists declarative binding.
type StripeOverride func(cred string, args map[string]any) (any, error)

// Stripe is an in-process, bring-your-own-key client. Every method builds a
// request from the binding and issues it with the client's *http.Client.
type Stripe struct {
	cred      string
	http      *http.Client
	overrides map[string]StripeOverride
}

type StripeOption func(*Stripe)

// StripeWithHTTPClient overrides the *http.Client (e.g. to inject a test transport).
func StripeWithHTTPClient(c *http.Client) StripeOption { return func(s *Stripe) { s.http = c } }

// StripeWithOverride registers a hand-written implementation for an escape-hatch action.
func StripeWithOverride(action string, fn StripeOverride) StripeOption {
	return func(s *Stripe) { s.overrides[action] = fn }
}

// NewStripe constructs a client for the given API key.
func NewStripe(credential string, opts ...StripeOption) *Stripe {
	s := &Stripe{cred: credential, http: http.DefaultClient, overrides: map[string]StripeOverride{}}
	for _, o := range opts {
		o(s)
	}
	return s
}

func (s *Stripe) execute(action string, args map[string]any) (any, error) {
	return ExecuteWith(s.http, STRIPE, action, args, s.cred)
}

func (s *Stripe) paginate(action string, args map[string]any) ([]any, error) {
	return PaginateWith(s.http, STRIPE, action, args, s.cred)
}

