// CancelSubscription is an ESCAPE-HATCH action: register an impl with StripeWithOverride("cancel_subscription", fn).
func (s *Stripe) CancelSubscription(args map[string]any) (any, error) {
	fn, ok := s.overrides["cancel_subscription"]
	if !ok {
		return nil, fmt.Errorf("stripe.cancel_subscription is an escape-hatch action; register an override")
	}
	return fn(s.cred, args)
}
